{
  "terms": [
    {
      "term": "Resistance",
      "simpleDefinition": "The total opposition to the flow of electric current within a specific component or length of wire.",
      "anchor": "Like the friction in a pipe that slows down water flow.",
      "misconception": "Believing that only 'resistors' have resistance; in reality, every cable and connection in a circuit has it."
    },
    {
      "term": "Resistivity",
      "simpleDefinition": "A fundamental property of a material that describes how strongly it opposes current, regardless of its shape or size.",
      "anchor": "The 'DNA' of a metal; copper has a low resistivity, while steel has a higher one.",
      "misconception": "Thinking resistivity and resistance are the same; resistivity is the material's nature, while resistance is the result of its size and shape."
    },
    {
      "term": "Voltage Drop",
      "simpleDefinition": "The reduction in electrical pressure as current passes through the resistance of a circuit.",
      "anchor": "The drop in water pressure at the end of a very long garden hose.",
      "misconception": "Thinking voltage is 'lost' or disappears; it is actually converted into other energy forms, usually heat."
    },
    {
      "term": "Ohm (Ω)",
      "simpleDefinition": "The unit used to measure electrical resistance.",
      "anchor": "The standard 'ruler' for measuring how hard it is for current to flow.",
      "misconception": "Confusing it with the unit for resistivity."
    },
    {
      "term": "Ohm-metre (Ωm)",
      "simpleDefinition": "The unit used to measure the resistivity of a material.",
      "anchor": "The specific measurement used to compare the quality of different conductors like copper and aluminium.",
      "misconception": "Using this unit to describe the total resistance of a circuit."
    }
  ],
  "anchorPhrases": [
    "Resistance is the opposition to flow.",
    "Resistivity is a property of the material itself.",
    "Voltage drop is the loss of electrical pressure over distance.",
    "Copper has lower resistivity than aluminium.",
    "Every conductor has some resistance."
  ],
  "misconceptionTargets": [
    "Resistivity and resistance are interchangeable terms.",
    "Cables have zero resistance because they are conductors.",
    "Voltage drop only occurs when there is a fault in the circuit.",
    "A thicker wire has more resistance because there is more metal to travel through."
  ]
}

{
  "teachChecks": [
    {
      "title": "Defining Resistance",
      "basicQuestions": [
        {
          "questionText": "What term describes the total opposition to the flow of electric current within a component or conductor?",
          "answerGuidance": [
            "Resistance"
          ],
          "hint": "Think about the general term for anything that slows down the flow of electricity.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What is the unit of measurement for electrical resistance?",
          "answerGuidance": [
            "Ohm",
            "Ohms",
            "Ω"
          ],
          "hint": "This unit is named after a famous scientist and uses a Greek symbol.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "Which letter is used as the symbol for resistance in electrical notation?",
          "answerGuidance": [
            "R"
          ],
          "hint": "It is the first letter of the word itself.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        }
      ],
      "deeperQuestionText": "Why must an electrician consider the resistance of the copper cables themselves, rather than just the resistance of the connected appliances?",
      "deeperAnswerGuidance": [
        "Every part of an installation has resistance",
        "Cables are not perfect conductors",
        "Wiring contributes to the total opposition in a circuit",
        "Resistance in cables causes energy to be used up as heat"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP3",
        "TP4"
      ],
      "hint": "Consider if a cable is a perfect path or if it acts like a pipe with internal friction."
    },
    {
      "title": "Defining Resistivity",
      "basicQuestions": [
        {
          "questionText": "What term describes the fundamental property of a material that defines its natural opposition to current, regardless of its shape?",
          "answerGuidance": [
            "Resistivity"
          ],
          "hint": "This is the 'DNA' of the material, not the total opposition of the finished wire.",
          "sourceTeachingPointIds": [
            "TP1",
            "TP3"
          ]
        },
        {
          "questionText": "What is the unit of measurement for resistivity?",
          "answerGuidance": [
            "Ohm-metre",
            "Ohm-metres",
            "Ωm"
          ],
          "hint": "It combines the unit of resistance with a unit of length.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "Which Greek letter is used as the symbol for resistivity?",
          "answerGuidance": [
            "Rho",
            "ρ"
          ],
          "hint": "It looks a bit like a lowercase 'p'.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        }
      ],
      "deeperQuestionText": "How does resistivity differ from resistance when comparing a short piece of copper wire to a very long piece of the same copper wire?",
      "deeperAnswerGuidance": [
        "Resistivity remains constant for both wires",
        "Resistance increases with the length of the wire",
        "Resistivity is a material property while resistance depends on dimensions",
        "The material 'DNA' does not change even if the shape does"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP3"
      ],
      "hint": "Think about which value is tied to the metal itself and which value is tied to the physical size."
    },
    {
      "title": "Resistance vs. Resistivity",
      "basicQuestions": [
        {
          "questionText": "What happens to the total resistance of a conductor if its length is increased?",
          "answerGuidance": [
            "Increases",
            "Higher",
            "Goes up"
          ],
          "hint": "The current has more material to travel through.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What happens to the resistance of a cable if its cross-sectional area is increased?",
          "answerGuidance": [
            "Decreases",
            "Lower",
            "Goes down"
          ],
          "hint": "Think of a wider pipe allowing more flow.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "Besides resistivity and length, what is the third physical factor that determines the resistance of a conductor?",
          "answerGuidance": [
            "Cross-sectional area",
            "Thickness",
            "Area"
          ],
          "hint": "This refers to how 'thick' or 'wide' the wire is.",
          "sourceTeachingPointIds": [
            "TP1",
            "TP3"
          ]
        }
      ],
      "deeperQuestionText": "If two cables are made of the same material but one is much thicker than the other, why does the thicker cable have a lower resistance?",
      "deeperAnswerGuidance": [
        "Larger cross-sectional area provides more paths for flow",
        "Increased thickness reduces the opposition to current",
        "Resistance is inversely related to the area of the conductor",
        "A wider path makes it easier for current to move"
      ],
      "deeperSourceTeachingPointIds": [
        "TP3",
        "TP5"
      ],
      "hint": "Compare a narrow single-lane road to a wide multi-lane motorway."
    },
    {
      "title": "The Concept of Voltage Drop",
      "basicQuestions": [
        {
          "questionText": "What term describes the reduction in electrical pressure as current passes through the resistance of a circuit?",
          "answerGuidance": [
            "Voltage drop"
          ],
          "hint": "It is the 'loss' of pressure over a distance.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "When electrical energy is used to overcome resistance in a conductor, what form of energy is it converted into?",
          "answerGuidance": [
            "Heat"
          ],
          "hint": "Think about what happens to a wire if it has to work hard to move current.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "How does the voltage available at the end of a long circuit compare to the voltage at the source?",
          "answerGuidance": [
            "Lower",
            "Less",
            "Reduced"
          ],
          "hint": "Some pressure is used up along the way.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        }
      ],
      "deeperQuestionText": "Why is voltage drop described as a conversion of energy rather than electricity simply 'disappearing'?",
      "deeperAnswerGuidance": [
        "Energy cannot be destroyed, only changed",
        "Electrical pressure is used to push current against resistance",
        "The energy used for movement is turned into heat",
        "Voltage drop represents the work done moving charge through the wire"
      ],
      "deeperSourceTeachingPointIds": [
        "TP2",
        "TP4"
      ],
      "hint": "Think about the law of conservation of energy and what happens to the 'lost' pressure."
    },
    {
      "title": "Linking Resistivity to Voltage Drop",
      "basicQuestions": [
        {
          "questionText": "Which set of UK regulations specifies the allowable limits for voltage drop in an installation?",
          "answerGuidance": [
            "BS 7671"
          ],
          "hint": "This is the 'Big Brown Book' of wiring regulations.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What is a likely physical effect on a motor if it is supplied by a circuit with excessive voltage drop?",
          "answerGuidance": [
            "Overheat",
            "Overheating",
            "Failure to start"
          ],
          "hint": "The motor won't have enough pressure to run efficiently.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "To minimize voltage drop over a long distance, should an electrician use a cable with a larger or smaller cross-sectional area?",
          "answerGuidance": [
            "Larger",
            "Thicker"
          ],
          "hint": "A bigger wire has less resistance.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "Why does choosing a material with a lower resistivity, such as copper instead of aluminium, help to reduce voltage drop in a circuit?",
      "deeperAnswerGuidance": [
        "Lower resistivity results in lower total resistance for the same size wire",
        "Lower resistance requires less electrical pressure to move current",
        "Less energy is converted to heat within the conductor",
        "More voltage remains available for the final load or appliance"
      ],
      "deeperSourceTeachingPointIds": [
        "TP2",
        "TP3",
        "TP4"
      ],
      "hint": "Connect the material's 'DNA' to the total resistance and then to the energy used up in the wire."
    }
  ]
}

{
  "guidedPractice": {
    "title": "Guided Practice: The Long Workshop Run",
    "objective": "Identify the outcome of resistance and resistivity in a long cable run.",
    "retrievalTextLines": [
      "Scenario: You are installing a 75-metre aluminum cable to a remote workshop.",
      "The aluminum has a specific inherent property (resistivity) that is higher than copper.",
      "Because the run is 75 metres long, the total opposition to current (resistance) is high.",
      "The supply starts at 230V, but due to the resistance, the voltage at the workshop is only 218V."
    ],
    "questionText": "What is the technical term for the 12V difference between the supply and the workshop?",
    "answerGuidance": [
      "Voltage drop",
      "Volt drop"
    ],
    "hint": "Think about the term used to describe the 'loss' or reduction in electrical pressure over the length of the conductor."
  },
  "practice": {
    "title": "Practice: Material Selection",
    "objective": "Distinguish between the total opposition in a circuit and the inherent property of the material used.",
    "retrievalTextLines": [
      "Scenario: A contractor is comparing two identical reels of cable. Both are 100 metres long and have the same cross-sectional area.",
      "Reel A is made of high-quality copper.",
      "Reel B is made of a lower-grade alloy.",
      "Reel B shows a much higher total resistance than Reel A, even though their physical dimensions are exactly the same."
    ],
    "questionText": "Which technical term describes the inherent material property (the 'DNA' of the metal) that causes Reel B to have higher resistance than Reel A?",
    "answerGuidance": [
      "Resistivity"
    ],
    "hint": "Remember that one term refers to the total opposition of the specific object (Resistance), while the other refers to the nature of the material itself."
  }
}

{
