    "objective": "Synthesize the relationship between material resistivity, physical length, and the resulting voltage drop in a practical circuit scenario.",
    "retrievalTextLines": [
      "A 10-metre copper sub-main is replaced with a 50-metre aluminium cable of the same thickness.",
      "Aluminium has a higher resistivity (ρ) than copper.",
      "The equipment at the end of the cable is now underperforming due to a lack of electrical pressure."
    ],
    "questionText": "Using the technical relationship between material and dimensions, explain why the new aluminium cable causes a significantly higher voltage drop than the original copper one.",
    "answerGuidance": [
      "Aluminium has a higher inherent resistivity than copper",
      "Increased length further increases the total resistance",
      "Higher resistance causes more electrical pressure to be used up",
      "Resulting in a larger voltage drop at the load"
    ],
    "hint": "Link the material's 'DNA' and the distance the current travels to the final loss of voltage."
  }
}

